mapper.select:
SELECT user_oid, user_id, user_nm_korn, inst_nm, mpno_pfx, ${schema}.fn_decrypt_aes(mpno_mid, #{aesKey}) AS mpno_mid, mpno_sfx, ${schema}.fn_decrypt_aes(eml_lcal, #{aesKey}) AS eml_lcal, eml_dmn, prvc_use_yn, prvc_reg_id, prvc_start_dt, prvc_end_dt, use_yn, reg_dt FROM ${schema}.user
user_authrt = 'ADMIN'
AND ( user_nm_korn LIKE CONCAT('%', #{filter.keyword}, '%') OR user_id LIKE CONCAT('%', #{filter.keyword}, '%') )
AND use_yn = #{filter.useYn}
AND DATE_FORMAT(reg_dt, '%Y-%m-%d') >= #{filter.regDtFrom} AND DATE_FORMAT(reg_dt, '%Y-%m-%d') <= #{filter.regDtTo}
AND CONCAT(mpno_pfx, ${schema}.fn_decrypt_aes(mpno_mid, #{aesKey}), mpno_sfx) LIKE CAST(CONCAT('%', #{filter.mpno}, '%') AS CHAR) collate utf8mb4_unicode_ci
AND eml_lcal LIKE CONCAT('%', #{filter.emlLcal}, '%')
AND eml_dmn LIKE CONCAT('%', #{filter.emlDmn}, '%')
AND prvc_use_yn = #{filter.prvcUseYn}
